SELECT chromosome_number, chromosome_type 
FROM chromosomes
WHERE chromosome_id = 0;

SELECT marker_name, marker_type 
FROM markers
WHERE marker_type = 'SNP';

SELECT COUNT(*)
FROM genetic_variations
WHERE chromosome_id = (SELECT chromosome_id FROM chromosomes WHERE chromosome_number = 3);

SELECT project_id, COUNT(*) as num_datasets
FROM project_datasets
GROUP BY project_id;

SELECT MAX(dom) AS max_dominance_effect, MIN(dom) AS min_dominance_effect
FROM genetic_variations
WHERE q_value > 0.01;

SELECT COUNT(DISTINCT user_id) AS unique_users_with_read_access
FROM user_permissions
WHERE read_access = 1;

SELECT dataset_name 
FROM project_datasets 
WHERE project_id = 1;
